class ProductionLoggingSystem private constructor(private val context: Context) {

    companion object {
        @Volatile
        private var instance: ProductionLoggingSystem? = null

        fun initialize(context: Context) {
            if (instance == null) {
                synchronized(this) {
                    if (instance == null) {
                        instance = ProductionLoggingSystem(context.applicationContext)
                    }
                }
            }
        }

        fun getInstance(): ProductionLoggingSystem {
            return instance ?: throw IllegalStateException("ProductionLoggingSystem must be initialized first")
        }
    }

    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val logDirectory: File = File(context.filesDir, "production_logs")

    init {
        setupTimber()
        if (!logDirectory.exists()) {
            logDirectory.mkdirs()
        }
    }

    private fun setupTimber() {
        Timber.plant(object : Timber.DebugTree() {
            override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                super.log(priority, tag, message, t)
                writeToFile(priority, tag, message, t)
            }

            override fun createStackElementTag(element: StackTraceElement): String {
                return String.format(
                    "[%s.%s:%d]",
                    element.className.substringAfterLast('.'),
                    element.methodName,
                    element.lineNumber
                )
            }
        })
    }

    private fun writeToFile(priority: Int, tag: String?, message: String, throwable: Throwable?) {
        try {
            val logFile = getLogFile()
            FileWriter(logFile, true).use { writer ->
                val timestamp = dateFormat.format(Date())
                val priorityStr = when (priority) {
                    Log.VERBOSE -> "VERBOSE"
                    Log.DEBUG -> "DEBUG"
                    Log.INFO -> "INFO"
                    Log.WARN -> "WARN"
                    Log.ERROR -> "ERROR"
                    Log.ASSERT -> "ASSERT"
                    else -> "UNKNOWN"
                }

                writer.append("$timestamp [$priorityStr] ${tag ?: "NO_TAG"}: $message\n")

                throwable?.let {
                    val sw = PrintWriter(writer)
                    it.printStackTrace(sw)
                    writer.append("\n")
                }
            }
        } catch (e: Exception) {
            Log.e("ProductionLoggingSystem", "Failed to write log to file", e)
        }
    }

    private fun getLogFile(): File {
        val dateStr = SimpleDateFormat("yyyy-MM-dd", Locale.US).format(Date())
        return File(logDirectory, "app_log_$dateStr.txt")
    }

    fun logAuthenticationAttempt(
        username: String,
        authMethod: String,
        success: Boolean,
        failureReason: String? = null,
        ipAddress: String? = null,
        deviceInfo: Map<String, String>? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "AUTHENTICATION_ATTEMPT")
            put("timestamp", dateFormat.format(Date()))
            put("username", username)
            put("auth_method", authMethod)
            put("success", success)
            put("ip_address", ipAddress ?: "unknown")

            if (!success && failureReason != null) {
                put("failure_reason", failureReason)
            }

            deviceInfo?.let {
                val deviceJson = JSONObject()
                it.forEach { (key, value) ->
                    deviceJson.put(key, value)
                }
                put("device_info", deviceJson)
            }
        }

        if (success) {
            Timber.i("AUTH_SUCCESS: %s", logData.toString(2))
        } else {
            Timber.w("AUTH_FAILURE: %s", logData.toString(2))
        }
    }

    fun logDatabaseQuery(
        queryType: String,
        tableName: String,
        query: String,
        parameters: Map<String, Any?>? = null,
        executionTimeMs: Long? = null,
        rowsAffected: Int? = null,
        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "DATABASE_QUERY")
            put("timestamp", dateFormat.format(Date()))
            put("query_type", queryType)
            put("table_name", tableName)
            put("query", query)

            parameters?.let {
                val paramsJson = JSONObject()
                it.forEach { (key, value) ->
                    paramsJson.put(key, value?.toString() ?: "null")
                }
                put("parameters", paramsJson)
            }

            executionTimeMs?.let { put("execution_time_ms", it) }
            rowsAffected?.let { put("rows_affected", it) }
            error?.let { put("error", it.message) }
        }

        if (error != null) {
            Timber.e(error, "DB_QUERY_ERROR: %s", logData.toString(2))
        } else {
            Timber.v("DB_QUERY: %s", logData.toString(2))
        }
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>,
        requestBody: String? = null,
        responseCode: Int? = null,
        responseBody: String? = null,
        responseHeaders: Map<String, String>? = null,
        durationMs: Long? = null,
        error: Throwable? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "API_REQUEST")
            put("timestamp", dateFormat.format(Date()))
            put("method", method)
            put("url", url)

            val headersJson = JSONObject()
            headers.forEach { (key, value) ->
                headersJson.put(key, if (key.lowercase().contains("authorization") || 
                                        key.lowercase().contains("token")) {
                    "***REDACTED***"
                } else {
                    value
                })
            }
            put("request_headers", headersJson)

            requestBody?.let { put("request_body", it) }
            responseCode?.let { put("response_code", it) }
            responseBody?.let { put("response_body", it) }
            durationMs?.let { put("duration_ms", it) }

            responseHeaders?.let {
                val respHeadersJson = JSONObject()
                it.forEach { (key, value) ->
                    respHeadersJson.put(key, value)
                }
                put("response_headers", respHeadersJson)
            }

            error?.let { put("error", it.message) }
        }

        if (error != null) {
            Timber.e(error, "API_REQUEST_ERROR: %s", logData.toString(2))
        } else if (responseCode != null && responseCode >= 400) {
            Timber.w("API_REQUEST_FAILED: %s", logData.toString(2))
        } else {
            Timber.d("API_REQUEST: %s", logData.toString(2))
        }
    }

    fun logException(
        exception: Throwable,
        context: String? = null,
        additionalData: Map<String, Any?>? = null,
        severity: ExceptionSeverity = ExceptionSeverity.ERROR
    ) {
        val logData = JSONObject().apply {
            put("event_type", "EXCEPTION")
            put("timestamp", dateFormat.format(Date()))
            put("exception_type", exception.javaClass.name)
            put("exception_message", exception.message ?: "No message")
            put("severity", severity.name)

            context?.let { put("context", it) }

            val stackTraceArray = JSONArray()
            exception.stackTrace.forEach { element ->
                stackTraceArray.put("${element.className}.${element.methodName}(${element.fileName}:${element.lineNumber})")
            }
            put("stack_trace", stackTraceArray)

            exception.cause?.let {
                put("cause_type", it.javaClass.name)
                put("cause_message", it.message ?: "No message")
            }

            additionalData?.let {
                val dataJson = JSONObject()
                it.forEach { (key, value) ->
                    dataJson.put(key, value?.toString() ?: "null")
                }
                put("additional_data", dataJson)
            }
        }

        when (severity) {
            ExceptionSeverity.FATAL -> Timber.e(exception, "FATAL_EXCEPTION: %s", logData.toString(2))
            ExceptionSeverity.ERROR -> Timber.e(exception, "EXCEPTION: %s", logData.toString(2))
            ExceptionSeverity.WARNING -> Timber.w(exception, "WARNING_EXCEPTION: %s", logData.toString(2))
        }
    }

