            put("timestamp", dateFormat.format(Date()))
            put("action", action)
            put("screen", screen)
            userId?.let { put("user_id", it) }

            additionalData?.let {
                val dataJson = JSONObject()
                it.forEach { (key, value) ->
                    dataJson.put(key, value?.toString() ?: "null")
                }
                put("additional_data", dataJson)
            }
        }

        Timber.i("USER_ACTION: %s", logData.toString(2))
    }

    fun logPerformanceMetric(
        metricName: String,
        durationMs: Long,
        category: String,
        additionalMetrics: Map<String, Any?>? = null
    ) {
        val logData = JSONObject().apply {
            put("event_type", "PERFORMANCE_METRIC")
            put("timestamp", dateFormat.format(Date()))
            put("metric_name", metricName)
            put("duration_ms", durationMs)
            put("category", category)

            additionalMetrics?.let {
                val metricsJson = JSONObject()
                it.forEach { (key, value) ->
                    metricsJson.put(key, value?.toString() ?: "null")
                }
                put("additional_metrics", metricsJson)
            }
        }

        Timber.d("PERFORMANCE: %s", logData.toString(2))
    }

    fun getAllLogFiles(): List<File> {
        return logDirectory.listFiles()?.toList() ?: emptyList()
    }

    fun getLogFileContent(file: File): String {
        return if (file.exists() && file.canRead()) {
            file.readText()
        } else {
            ""
        }
    }

    fun clearOldLogs(daysToKeep: Int = 7) {
        val cutoffTime = System.currentTimeMillis() - (daysToKeep * 24 * 60 * 60 * 1000L)
        logDirectory.listFiles()?.forEach { file ->
            if (file.lastModified() < cutoffTime) {
                file.delete()
                Timber.i("Deleted old log file: ${file.name}")
            }
        }
    }

    enum class ExceptionSeverity {
        WARNING,
        ERROR,
        FATAL
    }
}

object Logger {
    fun v(message: String, vararg args: Any?) {
        Timber.v(message, *args)
    }

    fun d(message: String, vararg args: Any?) {
        Timber.d(message, *args)
    }

    fun i(message: String, vararg args: Any?) {
        Timber.i(message, *args)
    }

    fun w(message: String, vararg args: Any?) {
        Timber.w(message, *args)
    }

    fun e(message: String, vararg args: Any?) {
        Timber.e(message, *args)
    }

    fun e(throwable: Throwable, message: String, vararg args: Any?) {
        Timber.e(throwable, message, *args)
    }

    fun wtf(message: String, vararg args: Any?) {
        Timber.wtf(message, *args)
    }

    fun wtf(throwable: Throwable, message: String, vararg args: Any?) {
        Timber.wtf(throwable, message, *args)
    }
}

